import { useState, useEffect, useCallback } from 'react'

export function usePersisted<T>(key: string, initial: T) {
  const [value, setValue] = useState<T>(() => {
    try {
      const stored = localStorage.getItem(key)
      return stored ? (JSON.parse(stored) as T) : initial
    } catch {
      return initial
    }
  })

  useEffect(() => {
    localStorage.setItem(key, JSON.stringify(value))
  }, [key, value])

  const reset = useCallback(() => setValue(initial), [initial])

  return [value, setValue, reset] as const
}

import { useCallback, useMemo } from 'react'
import type { FileNode } from '../types'
import { DEFAULT_FILES } from '../data/defaults'
import { usePersisted } from './usePersisted'

function findNode(nodes: FileNode[], id: string): FileNode | null {
  for (const n of nodes) {
    if (n.id === id) return n
    if (n.children) {
      const found = findNode(n.children, id)
      if (found) return found
    }
  }
  return null
}

function updateNode(nodes: FileNode[], id: string, updater: (n: FileNode) => FileNode): FileNode[] {
  return nodes.map((n) => {
    if (n.id === id) return updater(n)
    if (n.children) return { ...n, children: updateNode(n.children, id, updater) }
    return n
  })
}

function deleteNode(nodes: FileNode[], id: string): FileNode[] {
  return nodes
    .filter((n) => n.id !== id)
    .map((n) => (n.children ? { ...n, children: deleteNode(n.children, id) } : n))
}

function addChild(nodes: FileNode[], parentId: string, child: FileNode): FileNode[] {
  return nodes.map((n) => {
    if (n.id === parentId && n.type === 'folder') {
      return { ...n, children: [...(n.children ?? []), child] }
    }
    if (n.children) return { ...n, children: addChild(n.children, parentId, child) }
    return n
  })
}

function flattenFiles(nodes: FileNode[], prefix = ''): { id: string; path: string; node: FileNode }[] {
  const result: { id: string; path: string; node: FileNode }[] = []
  for (const n of nodes) {
    const path = prefix ? `${prefix}/${n.name}` : n.name
    if (n.type === 'file') result.push({ id: n.id, path, node: n })
    if (n.children) result.push(...flattenFiles(n.children, path))
  }
  return result
}

export function useFileSystem() {
  const [files, setFiles] = usePersisted<FileNode[]>('craftybot-files', DEFAULT_FILES)
  const [openTabs, setOpenTabs] = usePersisted<string[]>('craftybot-tabs', ['main-ts'])
  const [activeTab, setActiveTab] = usePersisted<string>('craftybot-active-tab', 'main-ts')

  const flatFiles = useMemo(() => flattenFiles(files), [files])

  const activeFile = useMemo(() => findNode(files, activeTab), [files, activeTab])

  const openFile = useCallback(
    (id: string) => {
      const node = findNode(files, id)
      if (!node || node.type !== 'file') return
      setOpenTabs((tabs) => (tabs.includes(id) ? tabs : [...tabs, id]))
      setActiveTab(id)
    },
    [files, setOpenTabs, setActiveTab],
  )

  const closeTab = useCallback(
    (id: string) => {
      setOpenTabs((tabs) => {
        const next = tabs.filter((t) => t !== id)
        if (activeTab === id && next.length > 0) {
          const idx = tabs.indexOf(id)
          setActiveTab(next[Math.max(0, idx - 1)] ?? next[0])
        }
        return next
      })
    },
    [activeTab, setOpenTabs, setActiveTab],
  )

  const updateContent = useCallback(
    (id: string, content: string) => {
      setFiles((f) => updateNode(f, id, (n) => ({ ...n, content })))
    },
    [setFiles],
  )

  const createFile = useCallback(
    (parentId: string, name: string) => {
      const id = `file-${Date.now()}`
      const ext = name.split('.').pop() ?? ''
      const langMap: Record<string, string> = {
        ts: 'typescript',
        js: 'javascript',
        json: 'json',
        md: 'markdown',
        css: 'css',
        html: 'html',
      }
      const child: FileNode = {
        id,
        name,
        type: 'file',
        content: '',
        language: langMap[ext] ?? 'plaintext',
      }
      setFiles((f) => addChild(f, parentId, child))
      openFile(id)
    },
    [setFiles, openFile],
  )

  const createFolder = useCallback(
    (parentId: string, name: string) => {
      const child: FileNode = { id: `folder-${Date.now()}`, name, type: 'folder', children: [] }
      setFiles((f) => addChild(f, parentId, child))
    },
    [setFiles],
  )

  const deleteFile = useCallback(
    (id: string) => {
      setFiles((f) => deleteNode(f, id))
      closeTab(id)
    },
    [setFiles, closeTab],
  )

  return {
    files,
    flatFiles,
    openTabs,
    activeTab,
    activeFile,
    openFile,
    closeTab,
    setActiveTab,
    updateContent,
    createFile,
    createFolder,
    deleteFile,
  }
}

import { useCallback } from 'react'
import type { ChatMessage } from '../types'
import { WELCOME_MESSAGES } from '../data/defaults'
import { usePersisted } from './usePersisted'

function generateResponse(input: string): string {
  const lower = input.toLowerCase()

  if (lower.includes('constr') || lower.includes('build')) {
    return `🧱 **Intenção detectada: BUILD**\n\nA ativar módulo de construção...\n- Analisar terreno\n- Calcular materiais\n- Iniciar blueprint\n\n*O agent vai começar a construir em ~3 segundos.*`
  }
  if (lower.includes('reconect') || lower.includes('econnreset') || lower.includes('servidor')) {
    return `🔄 **Persistência Extrema ativada**\n\nCiclo de reconexão infinito iniciado.\n\`\`\`\n[Agent] ECONNRESET detectado\n[Agent] Tentativa 1... conectando\n[Agent] Super-memória carregada ✓\n\`\`\`\nO bot está a reconectar-se ao servidor.`
  }
  if (lower.includes('test') || lower.includes('testar')) {
    return `✅ **Modo Teste**\n\nA executar suite de testes...\n- Unit tests: 12 passed\n- Integration: 3 passed\n- E2E agent: running\n\nPodes iterar no código enquanto corro os testes.`
  }
  if (lower.includes('plan')) {
    return `📋 **Plano gerado:**\n\n1. Analisar requisitos\n2. Implementar módulo core\n3. Testar no sandbox\n4. Deploy ao servidor\n5. Monitorizar reconexões\n\nQueres que execute o passo 1?`
  }
  if (lower.includes('help') || lower.includes('ajuda')) {
    return `**Comandos do Agent:**\n- "Constrói uma casa" → módulo BUILD\n- "Reconecta ao servidor" → persistência\n- "Testa o código" → suite de testes\n- "Faz um plano" → modo Plan\n\nTambém podes editar ficheiros no editor e correr comandos no terminal.`
  }

  return `Recebi: "${input}"\n\nComo **IA Proativa**, analisei o teu pedido. Queres que:\n- Execute uma ação automática?\n- Gere código no editor?\n- Corra testes no terminal?\n\nDiz-me mais detalhes ou usa **Plan** para um plano estruturado.`
}

export function useAgent() {
  const [messages, setMessages] = usePersisted<ChatMessage[]>('craftybot-chat', WELCOME_MESSAGES)
  const [isThinking, setIsThinking] = usePersisted<boolean>('craftybot-thinking', false)

  const sendMessage = useCallback(
    (content: string, planMode: boolean) => {
      const userMsg: ChatMessage = {
        id: `msg-${Date.now()}`,
        role: 'user',
        content: planMode ? `[Plan] ${content}` : content,
        timestamp: Date.now(),
      }
      setMessages((m) => [...m, userMsg])
      setIsThinking(true)

      setTimeout(() => {
        const reply = generateResponse(content)
        const assistantMsg: ChatMessage = {
          id: `msg-${Date.now()}-r`,
          role: 'assistant',
          content: reply,
          timestamp: Date.now(),
        }
        setMessages((m) => [...m, assistantMsg])
        setIsThinking(false)
      }, 800 + Math.random() * 700)
    },
    [setMessages, setIsThinking],
  )

  return { messages, isThinking, sendMessage }
}

import { useCallback, useState } from 'react'

export interface TerminalLine {
  type: 'input' | 'output' | 'error' | 'success'
  text: string
}

const HELP_TEXT = `CraftyBot Terminal v1.0
Comandos: help, clear, ls, cat <file>, npm <cmd>, node <file>, echo, pwd, agent status`

export function useTerminal(flatFiles: { path: string; node: { content?: string } }[]) {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'success', text: 'CraftyBot Terminal — escreve "help" para comandos' },
    { type: 'output', text: '~/projeto $' },
  ])
  const [history, setHistory] = useState<string[]>([])
  const [historyIdx, setHistoryIdx] = useState(-1)

  const runCommand = useCallback(
    (raw: string) => {
      const cmd = raw.trim()
      if (!cmd) return

      setHistory((h) => [...h, cmd])
      setHistoryIdx(-1)
      setLines((l) => [...l, { type: 'input', text: `~/projeto $ ${cmd}` }])

      const [command, ...args] = cmd.split(/\s+/)
      const arg = args.join(' ')

      const respond = (text: string, type: TerminalLine['type'] = 'output') => {
        setLines((l) => [...l, { type, text }, { type: 'output', text: '~/projeto $' }])
      }

      switch (command) {
        case 'help':
          respond(HELP_TEXT)
          break
        case 'clear':
          setLines([{ type: 'output', text: '~/projeto $' }])
          break
        case 'ls':
          respond(flatFiles.map((f) => f.path).join('\n') || '(vazio)')
          break
        case 'cat': {
          const file = flatFiles.find((f) => f.path.endsWith(arg) || f.path === arg)
          respond(file?.node.content ?? `ficheiro não encontrado: ${arg}`, file ? 'output' : 'error')
          break
        }
        case 'pwd':
          respond('/home/crafty/projeto')
          break
        case 'echo':
          respond(arg)
          break
        case 'npm':
          respond(`npm ${args.join(' ')}\n\n✓ Simulado — em produção corre no servidor real.`, 'success')
          break
        case 'node':
          respond(`Executando ${arg}...\n🤖 Agent output: connected=true, proactive=true`, 'success')
          break
        case 'agent':
          respond(
            `Agent Status:
  ● Conectado (simulado)
  ● IA Proativa: ON
  ● Super-memória: loaded
  ● Reconexões: 0 (última: nunca)`,
            'success',
          )
          break
        default:
          respond(`comando não encontrado: ${command}. Escreve "help".`, 'error')
      }
    },
    [flatFiles],
  )

  const navigateHistory = useCallback(
    (direction: 'up' | 'down'): string | null => {
      if (history.length === 0) return null
      let idx = historyIdx
      if (direction === 'up') {
        idx = idx < 0 ? history.length - 1 : Math.max(0, idx - 1)
      } else {
        idx = idx < 0 ? -1 : Math.min(history.length - 1, idx + 1)
        if (idx >= history.length - 1 && historyIdx >= 0) {
          setHistoryIdx(-1)
          return ''
        }
      }
      setHistoryIdx(idx)
      return history[idx] ?? null
    },
    [history, historyIdx],
  )

  return { lines, runCommand, navigateHistory }
}

