import { useState, useRef, useEffect } from 'react'
import {
  ArrowLeft,
  History,
  MessageSquarePlus,
  MoreVertical,
  ChevronDown,
  Plus,
  ArrowUp,
  CheckCircle2,
  Timer,
} from 'lucide-react'
import type { ChatMessage } from '../types'
import { AgentLogo } from './Logo'

interface AgentPanelProps {
  messages: ChatMessage[]
  isThinking: boolean
  onSend: (text: string, planMode: boolean) => void
  compact?: boolean
  onBack?: () => void
}

function renderMarkdown(text: string) {
  return text.split('\n').map((line, i) => {
    let html = line
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/`([^`]+)`/g, '<code>$1</code>')
    if (line.startsWith('```')) return null
    return <p key={i} dangerouslySetInnerHTML={{ __html: html }} />
  })
}

export function AgentPanel({ messages, isThinking, onSend, compact, onBack }: AgentPanelProps) {
  const [input, setInput] = useState('')
  const [planMode, setPlanMode] = useState(false)
  const [economy, setEconomy] = useState('Economy')
  const [checkpointOpen, setCheckpointOpen] = useState(false)
  const [workOpen, setWorkOpen] = useState(false)
  const scrollRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' })
  }, [messages, isThinking])

  const handleSend = () => {
    if (!input.trim()) return
    onSend(input.trim(), planMode)
    setInput('')
  }

  return (
    <div className={`agent-panel ${compact ? 'compact' : ''}`}>
      <header className="agent-header">
        {compact && onBack && (
          <button type="button" className="icon-btn" onClick={onBack} aria-label="Voltar">
            <ArrowLeft size={20} />
          </button>
        )}
        {compact && (
          <button type="button" className="icon-btn" aria-label="Histórico">
            <History size={20} />
          </button>
        )}
        <div className="agent-title">
          <AgentLogo size={compact ? 18 : 20} />
          <span>Agent</span>
        </motion>
        <div className="agent-header-actions">
          {compact && (
            <button type="button" className="icon-btn" aria-label="Nova conversa">
              <MessageSquarePlus size={20} />
            </button>
          )}
          <button type="button" className="icon-btn" aria-label="Menu">
            <MoreVertical size={20} />
          </button>
        </div>
      </header>

      <div className="agent-messages" ref={scrollRef}>
        {messages.map((msg) => (
          <div key={msg.id} className={`agent-msg ${msg.role}`}>
            {msg.role === 'assistant' ? (
              <div className="agent-msg-content">{renderMarkdown(msg.content)}</motion>
            ) : (
              <p>{msg.content}</p>
            )}
          </div>
        ))}
        {isThinking && (
          <div className="agent-thinking">
            <span className="dot" />
            <span className="dot" />
            <span className="dot" />
          </div>
        )}
      </div>

      <motion className="agent-status-list">
        <button
          type="button"
          className="status-row"
          onClick={() => setCheckpointOpen(!checkpointOpen)}
        >
          <CheckCircle2 size={16} className="status-icon success" />
          <span>Checkpoint made 4 months ago</span>
