import { useState } from 'react'
import { ChevronRight, File, Folder, FolderOpen, FilePlus, FolderPlus, Trash2 } from 'lucide-react'
import type { FileNode } from '../types'

interface FileTreeProps {
  nodes: FileNode[]
  activeId: string
  onOpen: (id: string) => void
  onCreateFile: (parentId: string, name: string) => void
  onCreateFolder: (parentId: string, name: string) => void
  onDelete: (id: string) => void
}

function TreeNode({
  node,
  depth,
  activeId,
  onOpen,
  onCreateFile,
  onCreateFolder,
  onDelete,
}: {
  node: FileNode
  depth: number
  activeId: string
  onOpen: (id: string) => void
  onCreateFile: (parentId: string, name: string) => void
  onCreateFolder: (parentId: string, name: string) => void
  onDelete: (id: string) => void
}) {
  const [expanded, setExpanded] = useState(depth < 2)
  const isFolder = node.type === 'folder'
  const isActive = node.id === activeId

  return (
    <motion>
      <div
        className={`tree-row ${isActive ? 'active' : ''}`}
        style={{ paddingLeft: 8 + depth * 14 }}
        onClick={() => (isFolder ? setExpanded(!expanded) : onOpen(node.id))}
        onDoubleClick={() => !isFolder && onOpen(node.id)}
        role="treeitem"
      >
        {isFolder ? (
          <>
            <ChevronRight size={14} className={`chevron ${expanded ? 'open' : ''}`} />
            {expanded ? <FolderOpen size={15} /> : <Folder size={15} />}
          </>
        ) : (
          <>
            <span className="chevron-spacer" />
            <File size={15} />
          </>
        )}
        <span className="tree-name">{node.name}</span>
        {node.id !== 'root' && (
          <button
            type="button"
            className="tree-delete"
            onClick={(e) => {
              e.stopPropagation()
              onDelete(node.id)
            }}
            aria-label="Apagar"
          >
            <Trash2 size={12} />
          </button>
        )}
      </div>
      {isFolder && expanded && node.children?.map((child) => (
        <TreeNode
          key={child.id}
          node={child}
          depth={depth + 1}
          activeId={activeId}
          onOpen={onOpen}
          onCreateFile={onCreateFile}
          onCreateFolder={onCreateFolder}
          onDelete={onDelete}
        />
      ))}
    </motion>
  )
}

export function FileTree({ nodes, activeId, onOpen, onCreateFile, onCreateFolder, onDelete }: FileTreeProps) {
  const root = nodes[0]
  if (!root) return null

  const handleNew = (type: 'file' | 'folder') => {
    const name = prompt(type === 'file' ? 'Nome do ficheiro:' : 'Nome da pasta:')
    if (!name) return
    if (type === 'file') onCreateFile('root', name)
    else onCreateFolder('root', name)
  }

  return (
    <div className="file-tree">
      <div className="file-tree-header">
        <span>EXPLORADOR</span>
        <div className="file-tree-actions">
          <button type="button" onClick={() => handleNew('file')} title="Novo ficheiro">
            <FilePlus size={14} />
          </button>
          <button type="button" onClick={() => handleNew('folder')} title="Nova pasta">
            <FolderPlus size={14} />
          </button>
        </div>
      </div>
      <div className="file-tree-body" role="tree">
        {root.children?.map((child) => (
          <TreeNode
            key={child.id}
            node={child}
            depth={0}
            activeId={activeId}
            onOpen={onOpen}
            onCreateFile={onCreateFile}
            onCreateFolder={onCreateFolder}
            onDelete={onDelete}
          />
        ))}
      </div>
    </div>
  )
}

