import { useState, useRef, useEffect } from 'react'
import type { TerminalLine } from '../hooks/useTerminal'

interface TerminalProps {
  lines: TerminalLine[]
  onCommand: (cmd: string) => void
  onHistoryNav: (dir: 'up' | 'down') => string | null
}

export function Terminal({ lines, onCommand, onHistoryNav }: TerminalProps) {
  const [input, setInput] = useState('')
  const bottomRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [lines])

  return (
    <motion className="terminal-panel">
      <div className="terminal-output">
        {lines.map((line, i) => (
          <div key={i} className={`terminal-line ${line.type}`}>
            {line.text}
          </div>
        ))}
        <div ref={bottomRef} />
      </div>
      <form
        className="terminal-input-row"
        onSubmit={(e) => {
          e.preventDefault()
          onCommand(input)
          setInput('')
        }}
      >
        <span className="terminal-prompt">$</span>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'ArrowUp') {
              e.preventDefault()
              const prev = onHistoryNav('up')
              if (prev !== null) setInput(prev)
            }
            if (e.key === 'ArrowDown') {
              e.preventDefault()
              const next = onHistoryNav('down')
              if (next !== null) setInput(next)
            }
          }}
          placeholder="help, ls, npm run dev, agent status..."
          spellCheck={false}
          autoComplete="off"
        />
      </form>
    </motion>
  )
}

