import {
  DEFAULT_SECRETS,
  DEFAULT_TABLES,
  DEFAULT_SESSIONS,
  DEFAULT_MEMORIES,
  DEFAULT_TASKS,
} from './data/defaults'
import { CraftyLogo } from './components/Logo'
import './App.css'

function useIsMobile() {
  const [mobile, setMobile] = useState(() =>
    typeof window !== 'undefined' ? window.innerWidth < 768 : false,
  )
  useEffect(() => {
    const onResize = () => setMobile(window.innerWidth < 768)
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [])
  return mobile
}

export default function App() {
  const isMobile = useIsMobile()
  const [nav, setNav] = useState<NavView>('agent')
  const [bottomPanel, setBottomPanel] = useState<BottomPanel>('agent')
  const [searchOpen, setSearchOpen] = useState(false)
  const [explorerOpen, setExplorerOpen] = useState(!isMobile)
  const [terminalOpen, setTerminalOpen] = useState(false)
  const [splitView, setSplitView] = useState(false)
  const [mobileShowEditor, setMobileShowEditor] = useState(false)

  const fs = useFileSystem()
  const agent = useAgent()
  const terminal = useTerminal(fs.flatFiles)

  const [secrets, setSecrets] = usePersisted('craftybot-secrets', DEFAULT_SECRETS)
  const [tables, setTables] = usePersisted('craftybot-db', DEFAULT_TABLES)
  const [sessions, setSessions] = usePersisted('craftybot-sessions', DEFAULT_SESSIONS)
  const [memories, setMemories] = usePersisted('craftybot-memories', DEFAULT_MEMORIES)
  const [tasks] = usePersisted('craftybot-tasks', DEFAULT_TASKS)

  const editorTabs = useMemo(
    () =>
      fs.openTabs
        .map((id) => {
          const f = fs.flatFiles.find((x) => x.id === id)
          return f ? { id, name: f.node.name } : null
        })
        .filter(Boolean) as { id: string; name: string }[],
    [fs.openTabs, fs.flatFiles],
  )

  const handleBottomChange = useCallback(
    (panel: BottomPanel) => {
      setBottomPanel(panel)
      if (panel === 'terminal') setTerminalOpen(true)
      if (panel === 'agent') setNav('agent')
      if (panel === 'split') setSplitView((s) => !s)
      if (panel === 'play') terminal.runCommand('npm run dev')
    },
    [terminal],
  )

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        setSearchOpen((o) => !o)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [])

  const renderMainPanel = () => {
    switch (nav) {
      case 'home':
        return <HomePanel onNavigate={(v) => setNav(v)} />
      case 'agent':
        return (
          <AgentPanel
            messages={agent.messages}
            isThinking={agent.isThinking}
            onSend={agent.sendMessage}
            compact={isMobile}
            onBack={isMobile ? () => setNav('home') : undefined}
          />
        )
      case 'history':
        return <HistoryPanel tasks={tasks} />
      case 'memory':
        return <MemoryPanel memories={memories} onChange={setMemories} />
      case 'sessions':
        return <SessionsPanel sessions={sessions} onChange={setSessions} />
      case 'secrets':
        return <SecretsPanel secrets={secrets} onChange={setSecrets} />
      case 'database':
        return <DatabasePanel tables={tables} onChange={setTables} />
      case 'auth':
        return <AuthPanel />
      default:
        return null
    }
  }

  const showEditor = nav === 'agent' || mobileShowEditor || ['home'].indexOf(nav) < 0

  if (isMobile) {
    return (
      <div className="app mobile">
        <header className="mobile-header">
          <button type="button" className="icon-btn" onClick={() => setNav('home')}>
            <Home size={20} />
          </button>
          <span className="mobile-title">CraftyBot</span>
          <button type="button" className="icon-btn">
            <MoreVertical size={20} />
          </button>
        </header>

        <main className="mobile-main">
          {nav === 'home' ? (
            <>
              {renderMainPanel()}
              <div className="mobile-quick-grid">
                {(['secrets', 'database', 'auth'] as NavView[]).map((v) => (
                  <button key={v} type="button" className="quick-btn" onClick={() => setNav(v)}>
                    {v === 'secrets' && '🔐 Secrets'}
                    {v === 'database' && '🗄 Database'}
                    {v === 'auth' && '👤 Auth'}
                  </button>
                ))}
                <button type="button" className="quick-btn" onClick={() => setNav('agent')}>
                  + Agent
                </button>
              </div>
            </>
          ) : nav === 'agent' ? (
            renderMainPanel()
          ) : (
            renderMainPanel()
          )}
        </main>

        <div className="mobile-search-bar">
          <button type="button" onClick={() => setExplorerOpen(!explorerOpen)}>
            📁
          </button>
          <button type="button" className="mobile-search" onClick={() => setSearchOpen(true)}>
            Search...
          </button>
          <button type="button" onClick={() => setSearchOpen(false)}>
            <X size={18} />
          </button>
        </div>

        <BottomBar active={bottomPanel} onChange={handleBottomChange} />
        <SearchModal
          open={searchOpen}
          onClose={() => setSearchOpen(false)}
          files={fs.flatFiles}
          onOpenFile={(id) => {
            fs.openFile(id)
            setMobileShowEditor(true)
          }}
        />
      </div>
    )
  }

  return (
    <div className="app desktop">
      <Sidebar
        active={nav}
        onNavigate={setNav}
        onNewTab={() => fs.createFile('root', 'untitled.ts')}
        searchOpen={searchOpen}
        onSearchToggle={() => setSearchOpen((o) => !o)}
        explorerOpen={explorerOpen}
        onExplorerToggle={() => setExplorerOpen((o) => !o)}
      />

      <div className="workspace">
        <div className={`workspace-top ${splitView ? 'split' : ''}`}>
          {explorerOpen && (
            <aside className="explorer-pane">
              <FileTree
                nodes={fs.files}
                activeId={fs.activeTab}
                onOpen={fs.openFile}
                onCreateFile={fs.createFile}
                onCreateFolder={fs.createFolder}
                onDelete={fs.deleteFile}
              />
            </aside>
          )}

          <div className="center-column">
            {nav === 'agent' || splitView ? (
              <div className={`agent-column ${splitView ? 'half' : 'full'}`}>
                {nav === 'agent' ? (
                  renderMainPanel()
                ) : (
                  <div className="panel-placeholder">
                    <CraftyLogo size={32} />
                    <p>Seleciona Agent na barra lateral</p>
                  </div>
                )}
              </div>
            ) : (
              <div className="main-panel-view">{renderMainPanel()}</div>
            )}

            {(splitView || nav === 'agent') && (
              <div className={`editor-column ${splitView ? 'half' : nav === 'agent' ? 'hidden' : 'full'}`}>
                {nav !== 'agent' || splitView ? (
                  <CodeEditor
                    tabs={editorTabs}
                    activeTab={fs.activeTab}
                    content={fs.activeFile?.content ?? ''}
                    language={fs.activeFile?.language ?? 'typescript'}
                    onSelectTab={fs.setActiveTab}
                    onCloseTab={fs.closeTab}
                    onChange={(v) => fs.updateContent(fs.activeTab, v)}
                  />
                ) : (
                  <button
                    type="button"
                    className="open-editor-btn"
                    onClick={() => setSplitView(true)}
                  >
                    Abrir Editor de Código
                  </button>
                )}
              </div>
            )}

            {nav !== 'agent' && !splitView && (
              <div className="editor-column full">
                <CodeEditor
                  tabs={editorTabs}
                  activeTab={fs.activeTab}
                  content={fs.activeFile?.content ?? ''}
                  language={fs.activeFile?.language ?? 'plaintext'}
                  onSelectTab={fs.setActiveTab}
                  onCloseTab={fs.closeTab}
                  onChange={(v) => fs.updateContent(fs.activeTab, v)}
                />
              </div>
            )}
          </div>
        </div>

        {terminalOpen && (
          <div className="terminal-pane">
            <div className="pane-header">
              <span>Terminal</span>
              <button type="button" className="icon-btn" onClick={() => setTerminalOpen(false)}>
                <X size={16} />
              </button>
            </div>
            <Terminal
              lines={terminal.lines}
              onCommand={terminal.runCommand}
              onHistoryNav={terminal.navigateHistory}
            />
          </div>
        )}

        {nav !== 'agent' && (
          <div className="main-panel-overlay">{renderMainPanel()}</motion>
        )}
      </div>

      <BottomBar active={bottomPanel} onChange={handleBottomChange} />

      <SearchModal
        open={searchOpen}
        onClose={() => setSearchOpen(false)}
        files={fs.flatFiles}
        onOpenFile={fs.openFile}
      />
    </div>
  )
}

import { useState, useEffect, useCallback, useMemo } from 'react'
import { Home, MoreVertical, X } from 'lucide-react'
import type { NavView, BottomPanel } from './types'
import { Sidebar } from './components/Sidebar'
import { AgentPanel } from './components/AgentPanel'
import { FileTree } from './components/FileTree'
import { CodeEditor } from './components/CodeEditor'
import { Terminal } from './components/Terminal'
import { BottomBar } from './components/BottomBar'
import { SearchModal } from './components/SearchModal'
import { HomePanel } from './components/panels/HomePanel'
import { HistoryPanel } from './components/panels/HistoryPanel'
import { MemoryPanel } from './components/panels/MemoryPanel'
import { SessionsPanel } from './components/panels/SessionsPanel'
import { SecretsPanel } from './components/panels/SecretsPanel'
import { DatabasePanel } from './components/panels/DatabasePanel'
import { AuthPanel } from './components/panels/AuthPanel'
import { useFileSystem } from './hooks/useFileSystem'
import { useAgent } from './hooks/useAgent'
import { useTerminal } from './hooks/useTerminal'
import { usePersisted } from './hooks/usePersisted'
import {
  DEFAULT_SECRETS,
  DEFAULT_TABLES,
  DEFAULT_SESSIONS,
  DEFAULT_MEMORIES,
  DEFAULT_TASKS,
} from './data/defaults'
import './App.css'

function useIsMobile() {
  const [mobile, setMobile] = useState(() =>
    typeof window !== 'undefined' ? window.innerWidth < 768 : false,
  )
  useEffect(() => {
    const onResize = () => setMobile(window.innerWidth < 768)
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [])
  return mobile
}

const DATA_VIEWS: NavView[] = ['home', 'history', 'memory', 'sessions', 'secrets', 'database', 'auth']

export default function App() {
  const isMobile = useIsMobile()
  const [nav, setNav] = useState<NavView>('agent')
  const [bottomPanel, setBottomPanel] = useState<BottomPanel>('agent')
  const [searchOpen, setSearchOpen] = useState(false)
  const [explorerOpen, setExplorerOpen] = useState(true)
  const [terminalOpen, setTerminalOpen] = useState(false)
  const [editorOpen, setEditorOpen] = useState(true)

  const fs = useFileSystem()
  const agent = useAgent()
  const terminal = useTerminal(fs.flatFiles)

  const [secrets, setSecrets] = usePersisted('craftybot-secrets', DEFAULT_SECRETS)
  const [tables, setTables] = usePersisted('craftybot-db', DEFAULT_TABLES)
  const [sessions, setSessions] = usePersisted('craftybot-sessions', DEFAULT_SESSIONS)
  const [memories, setMemories] = usePersisted('craftybot-memories', DEFAULT_MEMORIES)
  const [tasks] = usePersisted('craftybot-tasks', DEFAULT_TASKS)

  const editorTabs = useMemo(
    () =>
      fs.openTabs
        .map((id) => {
          const f = fs.flatFiles.find((x) => x.id === id)
          return f ? { id, name: f.node.name } : null
        })
        .filter(Boolean) as { id: string; name: string }[],
    [fs.openTabs, fs.flatFiles],
  )

  const handleBottomChange = useCallback(
    (panel: BottomPanel) => {
      setBottomPanel(panel)
      if (panel === 'terminal') {
        setTerminalOpen(true)
        return
      }
      if (panel === 'agent') setNav('agent')
      if (panel === 'split') setEditorOpen((e) => !e)
      if (panel === 'play') terminal.runCommand('npm run dev')
    },
    [terminal],
  )

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        setSearchOpen((o) => !o)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [])

  const renderDataPanel = () => {
    switch (nav) {
      case 'home':
        return <HomePanel onNavigate={(v) => setNav(v)} />
      case 'history':
        return <HistoryPanel tasks={tasks} />
      case 'memory':
        return <MemoryPanel memories={memories} onChange={setMemories} />
      case 'sessions':
        return <SessionsPanel sessions={sessions} onChange={setSessions} />
      case 'secrets':
        return <SecretsPanel secrets={secrets} onChange={setSecrets} />
      case 'database':
        return <DatabasePanel tables={tables} onChange={setTables} />
      case 'auth':
        return <AuthPanel />
      default:
        return null
    }
  }

  const editor = (
    <CodeEditor
      tabs={editorTabs}
      activeTab={fs.activeTab}
      content={fs.activeFile?.content ?? ''}
      language={fs.activeFile?.language ?? 'plaintext'}
      onSelectTab={fs.setActiveTab}
      onCloseTab={fs.closeTab}
      onChange={(v) => fs.updateContent(fs.activeTab, v)}
    />
  )

  if (isMobile) {
    return (
      <div className="app mobile">
        <header className="mobile-header">
          <button type="button" className="icon-btn" onClick={() => setNav('home')}>
            <Home size={20} />
          </button>
          <span className="mobile-title">CraftyBot</span>
          <button type="button" className="icon-btn" aria-label="Menu">
            <MoreVertical size={20} />
          </button>
        </header>

        <main className="mobile-main">
          {nav === 'home' ? (
            <>
              <HomePanel onNavigate={(v) => setNav(v)} />
              <div className="mobile-quick-grid">
                {(['secrets', 'database', 'auth', 'agent'] as NavView[]).map((v) => (
                  <button key={v} type="button" className="quick-btn" onClick={() => setNav(v)}>
                    {v.charAt(0).toUpperCase() + v.slice(1)}
                  </button>
                ))}
              </div>
            </>
          ) : nav === 'agent' ? (
            <AgentPanel
              messages={agent.messages}
              isThinking={agent.isThinking}
              onSend={agent.sendMessage}
              compact
              onBack={() => setNav('home')}
            />
          ) : (
            renderDataPanel()
          )}
        </main>

        <div className="mobile-search-bar">
          <button type="button" onClick={() => setExplorerOpen(!explorerOpen)} aria-label="Explorador">
            📁
          </button>
          <button type="button" className="mobile-search" onClick={() => setSearchOpen(true)}>
            Search...
          </button>
        </div>

        <BottomBar active={bottomPanel} onChange={handleBottomChange} />
        <SearchModal
          open={searchOpen}
          onClose={() => setSearchOpen(false)}
          files={fs.flatFiles}
          onOpenFile={fs.openFile}
        />
      </div>
    )
  }

  return (
    <div className="app desktop">
      <Sidebar
        active={nav}
        onNavigate={setNav}
        onNewTab={() => fs.createFile('root', 'untitled.ts')}
        searchOpen={searchOpen}
        onSearchToggle={() => setSearchOpen((o) => !o)}
        explorerOpen={explorerOpen}
        onExplorerToggle={() => setExplorerOpen((o) => !o)}
      />

      <div className="workspace">
        <div className="workspace-main">
          {explorerOpen && (
            <aside className="explorer-pane">
              <FileTree
                nodes={fs.files}
                activeId={fs.activeTab}
                onOpen={(id) => {
                  fs.openFile(id)
                  setEditorOpen(true)
                }}
                onCreateFile={fs.createFile}
                onCreateFolder={fs.createFolder}
                onDelete={fs.deleteFile}
              />
            </aside>
          )}

          <div className="content-area">
            {nav === 'agent' ? (
              <div className={`split-container ${editorOpen ? 'with-editor' : ''}`}>
                <section className="agent-section">
                  <AgentPanel
                    messages={agent.messages}
                    isThinking={agent.isThinking}
                    onSend={agent.sendMessage}
                  />
                </section>
                {editorOpen && <section className="editor-section">{editor}</section>}
              </div>
            ) : DATA_VIEWS.includes(nav) ? (
              <div className={`split-container ${editorOpen ? 'with-editor' : ''}`}>
                <section className="data-section">{renderDataPanel()}</section>
                {editorOpen && <section className="editor-section">{editor}</section>}
              </div>
            ) : null}
          </div>
        </motion>

        {terminalOpen && (
          <div className="terminal-pane">
            <div className="pane-header">
              <span>Terminal</span>
              <button type="button" className="icon-btn" onClick={() => setTerminalOpen(false)}>
                <X size={16} />
              </button>
            </div>
            <Terminal
              lines={terminal.lines}
              onCommand={terminal.runCommand}
              onHistoryNav={terminal.navigateHistory}
            />
          </div>
        )}
      </div>

      <BottomBar active={bottomPanel} onChange={handleBottomChange} />

      <SearchModal
        open={searchOpen}
        onClose={() => setSearchOpen(false)}
        files={fs.flatFiles}
        onOpenFile={fs.openFile}
      />
    </div>
  )
}

.app {
  display: flex;
  height: 100%;
  overflow: hidden;
}

.app.desktop {
  flex-direction: row;
}

.app.mobile {
  flex-direction: column;
}

/* Sidebar */
.sidebar {
  width: var(--sidebar-width);
  min-width: var(--sidebar-width);
  background: var(--bg-elevated);
  border-right: 1px solid var(--border-subtle);
  display: flex;
  flex-direction: column;
  padding: 12px 8px;
}

.sidebar-brand {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px 16px;
  font-weight: 700;
  font-size: 15px;
}

.crafty-logo {
  display: flex;
  align-items: center;
  justify-content: center;
}

.sidebar-nav {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
  overflow-y: auto;
}

.sidebar-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: var(--radius-sm);
  font-size: 13px;
  color: var(--text-secondary);
  text-align: left;
  width: 100%;
  transition: background 0.15s, color 0.15s;
}

.sidebar-item:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.sidebar-item.active {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.sidebar-item.active svg {
  color: var(--accent);
}

.sidebar-footer {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding-top: 8px;
  border-top: 1px solid var(--border-subtle);
}

.sidebar-icon-btn {
  width: 36px;
  height: 36px;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
}

.sidebar-icon-btn.active,
.sidebar-icon-btn:hover {
  background: var(--bg-hover);
  color: var(--accent);
}

.sidebar-search {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  background: var(--bg-input);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--text-muted);
  border: 1px solid transparent;
  width: 100%;
}

.sidebar-search:hover,
.sidebar-search.open {
  border-color: var(--border);
  color: var(--text-secondary);
}

.sidebar-search kbd {
  margin-left: auto;
  font-size: 10px;
  padding: 2px 5px;
  background: var(--bg-panel);
  border-radius: 4px;
  border: 1px solid var(--border);
}

/* Workspace */
.workspace {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  background: var(--bg-base);
}

.workspace-main {
  flex: 1;
  display: flex;
  min-height: 0;
}

.explorer-pane {
  width: 200px;
  min-width: 200px;
  border-right: 1px solid var(--border-subtle);
  background: var(--bg-elevated);
  display: flex;
  flex-direction: column;
}

.content-area {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
}

.split-container {
  flex: 1;
  display: flex;
  min-height: 0;
}

.split-container.with-editor .agent-section,
.split-container.with-editor .data-section {
  width: 42%;
  min-width: 280px;
  border-right: 1px solid var(--border-subtle);
}

.split-container:not(.with-editor) .agent-section,
.split-container:not(.with-editor) .data-section {
  flex: 1;
}

.editor-section {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
}

.agent-section,
.data-section {
  display: flex;
  flex-direction: column;
  min-height: 0;
  overflow: hidden;
}

.data-section {
  overflow-y: auto;
  padding: 16px;
}

/* Agent Panel */
.agent-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: var(--bg-panel);
  margin: 12px;
  border-radius: var(--radius);
  border: 1px solid var(--border-subtle);
  min-height: 0;
  overflow: hidden;
}

.agent-panel.compact {
  margin: 0;
  border-radius: 0;
  border: none;
}

.agent-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border-subtle);
}

.agent-title {
  display: flex;
  align-items: center;
  gap: 8px;
  font-weight: 600;
  flex: 1;
}

.agent-header-actions {
  display: flex;
  gap: 4px;
  margin-left: auto;
}

.agent-messages {
  flex: 1;
  overflow-y: auto;
  padding: 16px 20px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.agent-msg.assistant .agent-msg-content {
  font-size: 14px;
  line-height: 1.65;
  color: var(--text-secondary);
}

.agent-msg-content p {
  margin-bottom: 8px;
}

.agent-msg-content code {
  font-family: var(--font-mono);
  font-size: 12px;
  background: var(--bg-input);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--accent);
}

.agent-msg-content strong {
  color: var(--text-primary);
}

.agent-msg.user {
  align-self: flex-end;
  max-width: 85%;
}

.agent-msg.user p {
  background: var(--accent-dim);
  padding: 10px 14px;
  border-radius: 12px 12px 4px 12px;
  font-size: 14px;
}

.agent-thinking {
  display: flex;
  gap: 4px;
  padding: 8px;
}

.agent-thinking .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--accent);
  animation: bounce 1.2s infinite;
}

.agent-thinking .dot:nth-child(2) { animation-delay: 0.15s; }
.agent-thinking .dot:nth-child(3) { animation-delay: 0.3s; }

@keyframes bounce {
  0%, 80%, 100% { opacity: 0.3; transform: translateY(0); }
  40% { opacity: 1; transform: translateY(-4px); }
}

.agent-status-list {
  padding: 0 16px 8px;
  border-top: 1px solid var(--border-subtle);
}

.status-row {
  display: flex;
  align-items: center;
  gap: 10px;
  width: 100%;
  padding: 10px 0;
  font-size: 13px;
  color: var(--text-secondary);
  border-bottom: 1px solid var(--border-subtle);
}

.status-row:last-child {
  border-bottom: none;
}

.status-icon.success {
  color: var(--success);
}

.status-row .rotated {
  transform: rotate(180deg);
}

.status-detail {
  font-size: 12px;
  color: var(--text-muted);
  padding: 0 0 10px 26px;
}

.agent-input-area {
  padding: 12px 16px 16px;
  border-top: 1px solid var(--border-subtle);
}

.agent-input-area textarea {
  width: 100%;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 14px;
  font-size: 14px;
  resize: none;
  outline: none;
  margin-bottom: 10px;
}

.agent-input-area textarea:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 2px var(--accent-glow);
}

.agent-input-toolbar {
  display: flex;
  align-items: center;
  gap: 10px;
}

.input-tool-btn {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
}

.input-tool-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.plan-toggle {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 13px;
  color: var(--text-secondary);
  cursor: pointer;
}

.economy-select {
  margin-left: auto;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 6px 10px;
  font-size: 12px;
  outline: none;
}

.send-btn {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: var(--accent);
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: opacity 0.15s, transform 0.15s;
}

.send-btn:hover:not(:disabled) {
  transform: scale(1.05);
  background: var(--accent-dim);
}

.send-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

/* File tree */
.file-tree {
  flex: 1;
  display: flex;
  flex-direction: column;
  font-size: 13px;
}

.file-tree-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 12px;
  font-size: 11px;
  font-weight: 600;
