  color: var(--text-primary);
}

.file-tree-body {
  flex: 1;
  overflow-y: auto;
  padding-bottom: 12px;
}

.tree-row {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 8px 4px 0;
  cursor: pointer;
  color: var(--text-secondary);
  position: relative;
}

.tree-row:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.tree-row.active {
  background: var(--accent-glow);
  color: var(--accent);
}

.chevron {
  flex-shrink: 0;
  transition: transform 0.15s;
}

.chevron.open {
  transform: rotate(90deg);
}

.chevron-spacer {
  width: 14px;
}

.tree-name {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tree-delete {
  opacity: 0;
  padding: 2px;
  color: var(--text-muted);
}

.tree-row:hover .tree-delete {
  opacity: 1;
}

.tree-delete:hover {
  color: var(--error);
}

/* Code editor */
.code-editor {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
  background: var(--bg-base);
}

.editor-tabs {
  display: flex;
  background: var(--bg-elevated);
  border-bottom: 1px solid var(--border-subtle);
  overflow-x: auto;
}

.editor-tab {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 14px;
  font-size: 12px;
  color: var(--text-muted);
  border-right: 1px solid var(--border-subtle);
  white-space: nowrap;
}

.editor-tab.active {
  background: var(--bg-base);
  color: var(--text-primary);
  border-top: 2px solid var(--accent);
}

.tab-close {
  display: flex;
  padding: 2px;
  border-radius: 4px;
  opacity: 0.6;
}

.tab-close:hover {
  opacity: 1;
  background: var(--bg-hover);
}

.editor-body {
  flex: 1;
  min-height: 0;
}

.editor-empty {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  color: var(--text-muted);
  font-size: 14px;
}

/* Terminal */
.terminal-pane {
  height: 220px;
  border-top: 1px solid var(--border-subtle);
  display: flex;
  flex-direction: column;
  background: #0a0a0c;
}

.pane-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 12px;
  font-size: 12px;
  color: var(--text-muted);
  background: var(--bg-elevated);
  border-bottom: 1px solid var(--border-subtle);
}

.terminal-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
  font-family: var(--font-mono);
  font-size: 12px;
}

.terminal-output {
  flex: 1;
  overflow-y: auto;
  padding: 8px 12px;
}

.terminal-line {
  margin-bottom: 2px;
  white-space: pre-wrap;
  word-break: break-all;
}

.terminal-line.input {
  color: var(--accent);
}

.terminal-line.success {
  color: var(--success);
}

.terminal-line.error {
  color: var(--error);
}

.terminal-input-row {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  border-top: 1px solid var(--border-subtle);
}

.terminal-prompt {
  color: var(--success);
}

.terminal-input-row input {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  font-family: var(--font-mono);
  font-size: 12px;
}

/* Bottom bar */
.bottom-bar {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  height: var(--bottom-bar-height);
  background: var(--bg-elevated);
  border-top: 1px solid var(--border-subtle);
  padding: 0 16px;
}

.app.desktop .bottom-bar {
  position: relative;
}

.bottom-item {
  position: relative;
  width: 44px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
  border-radius: var(--radius-sm);
}

.bottom-item:hover {
  color: var(--text-secondary);
  background: var(--bg-hover);
}

.bottom-item.active {
  color: var(--accent);
}

.bottom-indicator {
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 20px;
  height: 2px;
  background: var(--accent);
  border-radius: 1px;
}

/* Data panels */
.data-panel {
  max-width: 900px;
}

.data-panel-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
  gap: 16px;
  flex-wrap: wrap;
}

.data-panel-header h2 {
  font-size: 20px;
  font-weight: 600;
}

.data-panel-desc {
  color: var(--text-muted);
  font-size: 13px;
  margin-bottom: 16px;
}

.btn-primary {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px;
  background: var(--accent);
  color: white;
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 500;
}

.btn-primary:hover {
  background: var(--accent-dim);
}

.btn-secondary {
  padding: 8px 14px;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 13px;
}

.btn-secondary:hover {
  background: var(--bg-hover);
}

.data-table-head,
.data-table-row {
  display: grid;
  grid-template-columns: 1fr 1.5fr 100px 40px;
  gap: 8px;
  align-items: center;
}

.data-table-head {
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--border-subtle);
}

.data-table-row {
  padding: 8px 0;
  border-bottom: 1px solid var(--border-subtle);
}

.data-table-row input,
.data-table-row select {
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 6px 8px;
  font-size: 13px;
  outline: none;
  width: 100%;
}

.secret-value-cell {
  display: flex;
  gap: 4px;
}

.secret-value-cell input {
  flex: 1;
}

.icon-btn {
  padding: 6px;
  border-radius: var(--radius-sm);
  color: var(--text-muted);
}

.icon-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.icon-btn.danger:hover {
  color: var(--error);
}

/* Database */
.table-tabs {
  display: flex;
  gap: 4px;
}

.table-tabs button {
  padding: 6px 12px;
  font-size: 12px;
  border-radius: var(--radius-sm);
  color: var(--text-muted);
  background: var(--bg-input);
}

.table-tabs button.active {
  background: var(--accent-glow);
  color: var(--accent);
}

.db-toolbar {
  margin-bottom: 12px;
}

.db-grid-wrap {
  overflow: auto;
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
}

.db-grid {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}

.db-grid th,
.db-grid td {
  padding: 8px 10px;
  border-bottom: 1px solid var(--border-subtle);
  text-align: left;
}

.db-grid th {
  background: var(--bg-elevated);
  color: var(--text-muted);
  font-size: 11px;
  text-transform: uppercase;
}

.db-grid td input {
  background: transparent;
  border: none;
  outline: none;
  width: 100%;
  font-size: 13px;
  color: var(--text-primary);
}

/* Auth */
.auth-panel .auth-form {
  max-width: 360px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.auth-icon-wrap {
  color: var(--accent);
}

.auth-form h3 {
  font-size: 18px;
}

.auth-form label {
  display: flex;
  flex-direction: column;
  gap: 6px;
  font-size: 13px;
  color: var(--text-secondary);
}

.auth-form input {
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  outline: none;
}

.auth-form input:focus {
  border-color: var(--accent);
}

.btn-primary.full {
  width: 100%;
  justify-content: center;
  padding: 12px;
}

.auth-hint {
  font-size: 12px;
  color: var(--text-muted);
  text-align: center;
}

.auth-profile {
  max-width: 360px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.profile-avatar {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background: var(--accent-glow);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent);
}

.role-badge {
  display: inline-block;
  padding: 4px 10px;
  background: var(--accent-glow);
  color: var(--accent);
  border-radius: 20px;
  font-size: 12px;
  width: fit-content;
}

.auth-stats {
  display: flex;
  flex-direction: column;
  gap: 8px;
  font-size: 13px;
  color: var(--text-secondary);
}

.auth-stats div {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* Home */
.home-panel {
  padding: 8px 0;
}

.home-hero h1 {
  font-size: 28px;
  margin-bottom: 8px;
  background: linear-gradient(135deg, #fff, var(--accent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.home-hero p {
  color: var(--text-secondary);
  margin-bottom: 20px;
}

.home-actions {
  display: flex;
  gap: 10px;
  margin-bottom: 32px;
}

.home-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 12px;
}

.home-card {
  background: var(--bg-panel);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  padding: 16px;
}

.home-card-icon {
  color: var(--accent);
  margin-bottom: 10px;
}

.home-card h3 {
  font-size: 14px;
  margin-bottom: 6px;
}

.home-card p {
  font-size: 12px;
  color: var(--text-muted);
  line-height: 1.5;
}

/* Lists */
.list-panel {
  width: 100%;
}

.task-list,
.session-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.task-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 14px;
  background: var(--bg-panel);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
}

.task-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.task-info span {
  font-size: 12px;
  color: var(--text-muted);
}

.task-item time {
  font-size: 12px;
  color: var(--text-muted);
}

.text-success { color: var(--success); }
.text-error { color: var(--error); }

.spin {
  animation: spin 1s linear infinite;
  color: var(--accent);
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.memory-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 12px;
}

.memory-card {
  background: var(--bg-panel);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  padding: 14px;
}

.memory-card header {
  display: flex;
  gap: 8px;
  margin-bottom: 10px;
}

.memory-title {
  flex: 1;
  background: transparent;
  border: none;
  font-weight: 600;
  font-size: 14px;
  outline: none;
}

.memory-card textarea {
  width: 100%;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px;
  font-size: 13px;
  resize: vertical;
  outline: none;
  margin-bottom: 10px;
}

.memory-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.tag {
  font-size: 11px;
  padding: 3px 8px;
  background: var(--accent-glow);
  color: var(--accent);
  border-radius: 20px;
}

.session-item button {
  display: flex;
  align-items: center;
  gap: 12px;
  width: 100%;
  padding: 12px 14px;
  background: var(--bg-panel);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  text-align: left;
}

.session-item.active button {
  border-color: var(--accent);
  background: var(--accent-glow);
}

.session-item strong {
  display: block;
  font-size: 14px;
}

.session-item span {
  font-size: 12px;
  color: var(--text-muted);
}

/* Search modal */
.search-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.6);
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 15vh;
  z-index: 1000;
}

.search-modal {
  width: 90%;
  max-width: 520px;
  background: var(--bg-panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  box-shadow: 0 24px 48px rgba(0, 0, 0, 0.5);
}

.search-input-wrap {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  border-bottom: 1px solid var(--border-subtle);
}

.search-input-wrap input {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  font-size: 15px;
}

.search-results {
  list-style: none;
  max-height: 320px;
  overflow-y: auto;
}

.search-results button {
  display: flex;
  align-items: center;
  gap: 10px;
  width: 100%;
  padding: 10px 16px;
  text-align: left;
  font-size: 13px;
  color: var(--text-secondary);
}

.search-results button:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.search-empty {
  padding: 20px;
  text-align: center;
  color: var(--text-muted);
  font-size: 13px;
}

/* Mobile */
.mobile-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border-subtle);
  background: var(--bg-elevated);
}

.mobile-title {
  font-weight: 700;
  font-size: 16px;
}

.mobile-main {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

.mobile-quick-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  padding: 16px;
}

.quick-btn {
  padding: 20px 16px;
  background: var(--bg-panel);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  font-size: 14px;
  font-weight: 500;
  text-align: center;
}

.quick-btn:hover {
  border-color: var(--accent);
  background: var(--accent-glow);
}

.mobile-search-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  border-top: 1px solid var(--border-subtle);
  background: var(--bg-elevated);
}

.mobile-search {
  flex: 1;
  padding: 10px 14px;
  background: var(--bg-input);
  border-radius: var(--radius);
  text-align: left;
  color: var(--text-muted);
  font-size: 14px;
}

@media (max-width: 767px) {
  .split-container.with-editor {
    flex-direction: column;
  }

  .split-container.with-editor .agent-section,
  .split-container.with-editor .data-section {
    width: 100%;
    min-width: 0;
    border-right: none;
    border-bottom: 1px solid var(--border-subtle);
  }
}

