import { Play, Monitor, Globe, Terminal, List, PanelRight } from 'lucide-react'
import type { BottomPanel } from '../types'
import { AgentLogo } from './Logo'

type BarItem =
  | { type: 'item'; id: BottomPanel; label: string; custom?: boolean }
  | { type: 'separator' }

const LEFT_ITEMS: BarItem[] = [
  { type: 'item', id: 'play', label: 'Run' },
  { type: 'item', id: 'preview', label: 'Preview' },
  { type: 'item', id: 'agent', label: 'Agent', custom: true },
  { type: 'item', id: 'web', label: 'Web' },
  { type: 'separator' },
  { type: 'item', id: 'terminal', label: 'Terminal' },
  { type: 'item', id: 'problems', label: 'Problems' },
  { type: 'item', id: 'split', label: 'Layout' },
]

const ICONS = {
  play: Play,
  preview: Monitor,
  web: Globe,
  terminal: Terminal,
  problems: List,
  split: PanelRight,
} as const

interface BottomBarProps {
  active: BottomPanel
  onChange: (panel: BottomPanel) => void
  mobile?: boolean
}

export function BottomBar({ active, onChange, mobile }: BottomBarProps) {
  return (
    <footer className={`bottom-bar ${mobile ? 'bottom-bar--mobile' : ''}`}>
      <motion className="bottom-bar-inner">
        {LEFT_ITEMS.map((entry, i) => {
          if (entry.type === 'separator') {
            return <span key={`sep-${i}`} className="bottom-separator" aria-hidden />
          }

          const { id, label, custom } = entry
          const Icon = ICONS[id as keyof typeof ICONS]

          return (
            <button
              key={id}
              type="button"
              className={`bottom-item ${active === id ? 'active' : ''}`}
              onClick={() => onChange(id)}
              title={label}
              aria-label={label}
              aria-current={active === id ? 'page' : undefined}
            >
              {custom ? <AgentLogo size={20} /> : Icon && <Icon size={20} strokeWidth={1.75} />}
              {active === id && <span className="bottom-indicator" />}
            </button>
          )
        })}
      </motion>
    </footer>
  )
}

